def _safe_get(obj, *names, default=None):
    for name in names:
        if hasattr(obj, name):
            value = getattr(obj, name)
            if value not in (None, ""):
                return value
    return default


def _build_worksheet_map(worksheet_metadata):
    worksheet_map = {}
