        region,
        "worksheet_name",
        "sheet_name",
        "worksheet_title",
        "title",
        "worksheet",
    )
    if sheet_name:
        return sheet_name
    worksheet_id = _safe_get(region, "worksheet_id", "sheet_id")
    return worksheet_map.get(worksheet_id, "unknown")


